refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image = imresize(image, [120 160]);
cameraMatrix = [180 0 80; 0 180 60; 0 0 1];
out = imundistort(image, cameraMatrix, [0.01 -0.002 0 0]);
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(out);
